#include <stdio.h>

int* make_value(int x) {
    int result = x * 2;
    return &result;
}

int main() {
    int* p = make_value(21);
    printf("%d\n", *p);
    return 0;
}

def has_pair_with_sum(nums, target):
    seen = set()
    for x in nums:
        if target - x in seen:
            return True
        seen.add(x)
    return False
